const Options = () => {
    const bank = [{name: 'Bank Name', rate: 'Bank Rate', updated: "Bank Update"}]
    return(
        <table className="table table-striped table-sm">
            <thead>
                <tr>
                    <th>Bank</th>
                    <th>Rate</th>
                    <th>Updated</th>
                </tr>
            </thead>
            <tbody>
            {bank.map((data, i)=>{
                return (
                    <tr key={i}>
                        <td>{data.name}</td>
                        <td>{data.rate}</td>
                        <td>{data.updated}</td>
                    </tr>
                )
            })}
            </tbody>
        </table>
     )
   }
   
   export default Options;